const state = {
  flat: [],
  current: null
};

function $(id){ return document.getElementById(id); }
function save(key,val){ localStorage.setItem(key, JSON.stringify(val)); }
function load(key, fallback){ try{ return JSON.parse(localStorage.getItem(key)) ?? fallback; }catch(e){ return fallback; } }
function esc(s){ return String(s ?? "").replace(/[&<>"]/g, m => ({"&":"&amp;","<":"&lt;",">":"&gt;",'"':"&quot;"}[m])); }
function severityClass(sev){
  const s = String(sev||"").toLowerCase();
  if(s.includes("高") || s.includes("critical")) return "bad";
  if(s.includes("中") || s.includes("mid")) return "warn";
  return "good";
}
function severityBadge(sev){ return `<span class="badge ${severityClass(sev)}">${esc(sev||"未標示")}</span>`; }
function isCodeItem(item){ return /0x|^[0-9]{4}｜|boot_device|memory_management|critical_process_died|exception|page_fault|kmode/i.test(item.title); }
function isWindowsCategory(catKey){ return catKey.startsWith("windows_"); }
function flattenData(){
  const flat = [];
  Object.entries(APP.dataset).forEach(([key,cat])=>{
    (cat.items||[]).forEach((item,idx)=>{
      flat.push({
        catKey:key,
        catLabel:cat.label,
        icon:cat.icon,
        idx,
        title:item.title,
        severity:item.severity || "中",
        steps:item.steps || [],
        causes:item.causes || [],
        tests:item.tests || [],
        fix:item.fix || [],
      });
    });
  });
  state.flat = flat;
}
function navTo(page){
  document.querySelectorAll('.navbtn').forEach(a=>a.classList.toggle('active', a.dataset.page===page));
  document.querySelectorAll('main section[id^="page-"]').forEach(sec=>sec.classList.add('hide'));
  $('page-'+page).classList.remove('hide');
  const titles = {
    dashboard:["故障總覽","最常見故障類別、門市快速入口、排查重點。"],
    diagnosis:["故障樹檢測","直接按類別與情境查看完整排查流程。"],
    codes:["錯誤碼 / 關鍵字查詢","輸入代碼、藍屏、症狀，快速縮小範圍。"],
    symptom:["症狀快速判斷","勾選現象，列出最可能的故障情境。"],
    report:["檢測結論單","列印現場判斷結論，不再綁維修單。"]
  };
  $('pageTitle').textContent = titles[page][0];
  $('pageHint').textContent = titles[page][1];
  closeMobileMenu();
}
