function openMobileMenu(){ if(!isMobile()) return; $('side').classList.add('open'); $('mobileOverlay').classList.add('show'); $('mobileMenuBtn').setAttribute('aria-expanded','true'); document.body.classList.add('menu-open'); }
function closeMobileMenu(){ $('side').classList.remove('open'); $('mobileOverlay').classList.remove('show'); $('mobileMenuBtn').setAttribute('aria-expanded','false'); document.body.classList.remove('menu-open'); }
function toggleMobileMenu(){ $('side').classList.contains('open') ? closeMobileMenu() : openMobileMenu(); }

