function buildSearchResults(){
  const q = $('codeSearch').value.trim().toLowerCase();
  const mode = $('codeFilter').value;
  let list = state.flat.filter(x=>{
    if(mode==='windows' && !isWindowsCategory(x.catKey)) return false;
    if(mode==='hardware' && isWindowsCategory(x.catKey)) return false;
    if(!q) return true;
    const hay = [x.title, x.catLabel, ...x.steps, ...x.causes, ...x.tests, ...x.fix].join(' ').toLowerCase();
    return hay.includes(q);
  });
  list = list.slice(0, 60);
  $('searchStats').textContent = q ? `找到 ${list.length} 筆結果` : `目前顯示 ${list.length} 筆`;
  $('searchBody').innerHTML = list.map(x=>`
    <tr>
      <td><b style="color:#fff">${esc(x.title)}</b></td>
      <td>${esc(x.catLabel)}</td>
      <td>${severityBadge(x.severity)}</td>
      <td>${esc((x.causes[0] || x.steps[0] || '—'))}</td>
      <td><button type="button" class="ghost" onclick="jumpToItem('${x.catKey}', ${x.idx})">查看</button></td>
