function runSymptomJudge(){
  const picked = [...document.querySelectorAll('[data-sym].active')].map(x=>x.dataset.sym);
  if(!picked.length){ $('symptomResult').innerHTML = '請至少勾選一個症狀。'; return; }
  const scored = state.flat.map(item=>{
    const hay = [item.title, item.catLabel, ...item.steps, ...item.causes, ...item.tests, ...item.fix].join(' ').toLowerCase();
    let score = 0;
    const hits = [];
    picked.forEach(id=>{
      const sym = SYMPTOMS.find(s=>s.id===id);
      if(!sym) return;
      let local = 0;
      sym.keys.forEach(k=>{ if(hay.includes(k.toLowerCase())) local += 1; });
      if(local){ score += local; hits.push(sym.label); }
    });
    if(item.title.includes("Q-Code") || item.title.includes("Vanguard") || item.title.includes("BitLocker")) score += 0.35;
    if(severityClass(item.severity)==='bad') score += 0.2;
    return {...item, score, hits:[...new Set(hits)]};
  }).filter(x=>x.score>0).sort((a,b)=>b.score-a.score).slice(0,6);

  $('symptomResult').innerHTML = scored.length ? `
    <b style="color:#fff">最可能情境（Top 3 優先看）</b>
    <ol class="list">${scored.map((x,i)=>`<li>
      <a href="#" onclick="jumpToItem('${x.catKey}', ${x.idx}); return false;"><b style="color:#fff">${esc(x.title)}</b></a>
      ｜${esc(x.catLabel)}｜${x.score.toFixed(2)} 分
      ${i<3 ? '<span class="badge good">Top '+(i+1)+'</span>' : ''}
      <br><span class="small" style="color:#fff">${x.hits.length ? '命中：' + esc(x.hits.join('、')) : '依關鍵字接近度排序'}</span>
    </li>`).join('')}</ol>
  ` : '沒有找到足夠接近的情境，建議改用關鍵字查詢。';
}
