function checkStorageLamp(){
  const dot = $('storageDot'); const text = $('storageText');
  if(!dot || !text) return;
  fetch('api.php?action=ping', {cache:'no-store'})
    .then(r => r.json())
    .then(data => {
      if(data.status==='ok' && data.mode==='nas'){ dot.style.background='#22c55e'; text.textContent='NAS 同步中'; }
