function normalizeAiText(str){
  let s = (str || '').toString().toLowerCase();
  const replacements = [
    [/wi\s*-?\s*fi/gi,'wifi'],
    [/藍頻/gi,'藍屏'],
    [/不過電|開不起來|開機不了|不開機/gi,'無法開機'],
    [/抓不到\s*wi\s*-?\s*fi|找不到\s*wi\s*-?\s*fi/gi,'找不到 wifi'],
    [/抓不到網路|找不到網路|沒網路|無網路/gi,'網路異常'],
    [/沒畫面|無畫面|不顯示|沒顯示|黑屏/gi,'黑畫面'],
    [/會亮但沒畫面|有亮沒畫面|有通電沒畫面|有燈沒畫面/gi,'開機有燈但無畫面 黑畫面'],
    [/完全沒反應|完全無反應|按電源沒反應/gi,'完全沒反應 無法開機'],
    [/一直當機|常當機|會卡死|卡住不動|freeze|hang/gi,'當機 系統不穩'],
    [/更新後進不了系統|更新後無法進入系統|更新完進不去/gi,'windows更新失敗 無法進入系統'],
    [/進桌面後一直當機|進桌面就當機|進桌面會當機/gi,'登入後黑畫面 進桌面 當機 系統不穩'],
    [/連不上wifi|wifi連不上|無法連wifi|抓不到\s*wifi/gi,'wifi 連不上 找不到 wifi'],
    [/無線網路/gi,'wifi'],
    [/重開機迴圈|一直重開|自動重開/gi,'一直重開機循環'],
    [/桌面出不來|進桌面黑畫面/gi,'登入後黑畫面 桌面不出現'],
    [/更新後/gi,'更新後 windows更新失敗'],
    [/抓不到/gi,'找不到']
  ];
  replacements.forEach(([pattern, to]) => { s = s.replace(pattern, to); });
  return s
    .replace(/[｜|/\\,_\-]+/g,' ')
    .replace(/\s+/g,' ')
    .trim();
}

function aiExpandTerms(raw){
  const set = new Set(raw.split(/\s+/).filter(Boolean));
  const push = (...arr)=>arr.forEach(x=>x && set.add(x));
  if(/黑畫面|無訊號|顯示|螢幕/.test(raw)) push('黑畫面','無訊號','顯示','螢幕');
  if(/無法開機|完全沒反應|不過電|斷電/.test(raw)) push('無法開機','不過電','完全沒反應','電源');
  if(/當機|系統不穩|卡頓|freeze|lag/.test(raw)) push('當機','系統','不穩','桌面','重開機');
  if(/wifi|網路異常|網路|連不上/.test(raw)) push('wifi','網路','連線','無線');
  if(/更新|windows更新失敗|修復|進不了系統/.test(raw)) push('更新','修復','系統','無法進入');
  if(/藍屏|bsod/.test(raw)) push('藍屏','bsod','stop');
  return [...set];
}
function aiBigramSet(str){
  const s = normalizeAiText(str).replace(/\s+/g,'');
  const set = new Set();
  for(let i=0;i<s.length-1;i++) set.add(s.slice(i,i+2));
  return set;
}
function aiJaccard(a,b){
  if(!a.size || !b.size) return 0;
  let inter = 0;
  for(const x of a){ if(b.has(x)) inter++; }
  return inter / (a.size + b.size - inter || 1);
}


const AI_HELPER = {
  opened:false,
  lastAnalysis:null,
  routeTo(page){ navTo(page); this.open(); },
  open(){ $('aiPanel').classList.add('open'); this.opened = true; },
  close(){ $('aiPanel').classList.remove('open'); this.opened = false; },
  toggle(){ this.opened ? this.close() : this.open(); },
  append(role, html){
    const body = $('aiBody');
    const last = body.lastElementChild;
    if(last && last.classList.contains(role) && last.innerHTML === html) return;
    const el = document.createElement('div');
    el.className = `ai-msg ${role}`;
    el.innerHTML = html;
    body.appendChild(el);
    body.scrollTop = body.scrollHeight;
  },
  ask(text){
    const q = (text || '').trim();
    if(!q) return;
    this.append('user', esc(q));
    const res = this.answer(q);
    this.append('bot', res);
  },
  answer(q){
    const text = normalizeAiText(q);
    if(/開始|怎麼用|使用|教我|新手/.test(q)) return this.renderStartGuide();
    if(/報告|紀錄|列印|結論/.test(q)) return this.renderReportGuide();
    if(/症狀|判斷|不知道哪一類|不確定/.test(q)) return this.renderSymptomGuide();

    const analysis = this.analyze(q);
    this.lastAnalysis = analysis;

    if(analysis.matches.length){
      return this.renderDiagnosisCard(analysis);
    }
    if(analysis.groupTips.length){
      return `我先幫你判斷比較接近這些故障類別：<b>${analysis.groupTips.map(esc).join('、')}</b>。<br>建議先切到故障檢測看同類型情境，或換成更明確的問法，例如「黑畫面但有進 BIOS」、「插電不充電」、「Vanguard 9003」。<div class="ai-links"><button class="ai-link" onclick="AI_HELPER.routeTo('diagnosis')"><span>前往故障檢測</span><b>→</b></button><button class="ai-link ghostLink" onclick="AI_HELPER.routeTo('symptoms')"><span>改用症狀判斷</span><b>→</b></button></div>`;
    }
    return `我先幫你抓到一個大方向，但目前沒有命中非常接近的單一情境。<br>建議先用 <b>症狀判斷</b> 收斂，再到 <b>故障檢測</b> 交叉確認。你也可以直接改問像「會亮但沒畫面」、「進桌面後一直當機」、「抓不到 Wi‑Fi」、「更新後進不了系統」這種門市描述。<div class="ai-links"><button class="ai-link" onclick="AI_HELPER.routeTo('symptoms')"><span>前往症狀判斷</span><b>→</b></button><button class="ai-link ghostLink" onclick="AI_HELPER.routeTo('diagnosis')"><span>前往故障檢測</span><b>→</b></button></div>`;
  },
  renderStartGuide(){
    return `建議你這樣開始：<br>1. 已知道大方向 → 直接用 <b>故障檢測</b>。<br>2. 症狀很多還不確定 → 用 <b>症狀判斷</b>。<br>3. 手上有藍屏碼、錯誤碼、Q‑Code → 用 <b>錯誤碼/關鍵字搜尋</b>。<div class="ai-links"><button class="ai-link" onclick="AI_HELPER.routeTo('diagnosis')"><span>前往故障檢測</span><b>→</b></button><button class="ai-link ghostLink" onclick="AI_HELPER.routeTo('symptoms')"><span>前往症狀判斷</span><b>→</b></button><button class="ai-link ghostLink" onclick="AI_HELPER.routeTo('codes')"><span>前往錯誤碼搜尋</span><b>→</b></button></div>`;
  },
  renderReportGuide(){
    return `要整理給客人或同仁的結論，直接到 <b>檢測結論單</b>，再用「帶入目前選定情境」就能快速生成。若你是從 AI 找到情境，也可以直接按下面的「帶入 AI 建議」。<div class="ai-links"><button class="ai-link" onclick="AI_HELPER.routeTo('report')"><span>前往檢測結論單</span><b>→</b></button>${this.lastAnalysis && this.lastAnalysis.best ? `<button class="ai-link ghostLink" onclick="AI_HELPER.fillReportFromScenario(${this.lastAnalysis.best.idx})"><span>帶入 AI 建議</span><b>＋</b></button>`:''}</div>`;
  },
  renderSymptomGuide(){
    return `若你現在還不確定是哪一類，先到 <b>症狀判斷</b> 勾選現象，系統會幫你排出最接近的情境。這個方式很適合客人描述很亂、你想先快速收斂方向的情況。<div class="ai-links"><button class="ai-link" onclick="AI_HELPER.routeTo('symptoms')"><span>前往症狀判斷</span><b>→</b></button></div>`;
  },
  analyze(q){
    const matches = this.searchScenarios(q).slice(0,5);
    const best = matches[0] || null;
    const groupTips = this.matchGroups(q);
    const tags = this.extractTags(q);
    const risk = best ? (best.severity || '中') : '中';
    return { query:q, matches, best, groupTips, tags, risk };
  },
  extractTags(q){
    const raw = normalizeAiText(q);
    const tags = [];
    if(/無法開機|開機不了|不過電|斷電/.test(raw)) tags.push('開機異常');
    if(/黑畫面|無訊號|螢幕|顯示/.test(raw)) tags.push('顯示異常');
    if(/藍屏|bsod|memory_management|critical_process_died|page_fault|irql/.test(raw)) tags.push('藍屏');
    if(/wifi|網路|乙太|無線|連不上/.test(raw)) tags.push('網路異常');
    if(/充電|電池|adapter|變壓器/.test(raw)) tags.push('供電/充電');
    if(/當機|卡頓|很慢|lag|freeze/.test(raw)) tags.push('效能/穩定度');
    if(/更新|修復|bitlocker|0x|q-code|錯誤碼/.test(raw)) tags.push('系統/錯誤碼');
    return [...new Set(tags)].slice(0,4);
  },
  renderDiagnosisCard(analysis){
    const best = analysis.best;
    const topList = analysis.matches.slice(0,3).map((x,i)=>`<button class="ai-link" onclick="jumpToItem('${x.catKey}', ${x.idx}); AI_HELPER.open();"><span><b>${esc(x.title)}</b><br><span class="small">${esc(x.catLabel)}｜${esc(x.severity)}｜命中 ${x.score}</span></span><b>${i===0?'優先看':'查看'}</b></button>`).join('');
    const steps = (best.steps||[]).slice(0,3).map(x=>`<li>${esc(x)}</li>`).join('');
    const causes = (best.causes||[]).slice(0,3).map(x=>`<li>${esc(x)}</li>`).join('');
    const tests = (best.tests||[]).slice(0,3).map(x=>`<li>${esc(x)}</li>`).join('');
    const fix = (best.fix||[]).slice(0,3).map(x=>`<li>${esc(x)}</li>`).join('');
    const tags = analysis.tags.length ? `<div class="ai-tags">${analysis.tags.map(x=>`<span class="ai-tag">${esc(x)}</span>`).join('')}</div>` : '';
    const follow = this.followHint(analysis);
    return `
      <div class="ai-card">
        <h4>門市工程師初步判斷</h4>
        ${tags}
        <div class="ai-grid">
          <div class="ai-mini">
            <b>最接近情境</b>
            <div>${esc(best.title)}</div>
            <div style="margin-top:6px">${esc(best.catLabel)}｜風險 ${esc(best.severity)}</div>
          </div>
          <div class="ai-mini">
            <b>現場處理原則</b>
            <div>先做不破壞資料、可快速排除的檢測，再決定是否拆機、重灌或更換零件。</div>
          </div>
          <div class="ai-mini"><b>優先檢查</b><ul>${steps || '<li>先確認電源 / 基本連接</li>'}</ul></div>
          <div class="ai-mini"><b>可能原因</b><ul>${causes || '<li>先從最常見的硬體/系統原因排查</li>'}</ul></div>
          <div class="ai-mini"><b>建議測試</b><ul>${tests || '<li>先做基本交叉測試</li>'}</ul></div>
          <div class="ai-mini"><b>建議處置</b><ul>${fix || '<li>依檢測結果進一步處理</li>'}</ul></div>
        </div>
        <div class="ai-follow">${follow}</div>
      </div>
      <div class="ai-links">
        ${topList}
        <button class="ai-link ghostLink" onclick="AI_HELPER.fillReportFromScenario(${best.idx})"><span>帶入檢測結論單</span><b>＋</b></button>
        <button class="ai-link ghostLink" onclick="AI_HELPER.routeTo('symptoms')"><span>改用症狀判斷交叉確認</span><b>→</b></button>
      </div>`;
  },
  followHint(analysis){
    const raw = normalizeAiText(analysis.query);
    if(/黑畫面|無訊號|顯示/.test(raw)) return '若有風扇轉但沒畫面，先分辨是「主機沒過 POST」還是「顯示輸出異常」，這兩個方向完全不同。';
    if(/無法開機|不過電|斷電/.test(raw)) return '若完全沒反應，先查供電鏈；若亮一下就熄滅，再往短路、RAM、主板保護方向查。';
    if(/藍屏|bsod/.test(raw)) return '藍屏先記代碼，再看是記憶體、驅動還是儲存裝置方向，效率會高很多。';
    if(/網路|wifi/.test(raw)) return '網路問題先分清楚是「完全抓不到介面」還是「有介面但連不上」，處理方式差很多。';
    return '若客人描述很多症狀，建議先抓主訴，再依最關鍵症狀做第一輪排除。';
  },
  fillReportFromScenario(idx){
    const item = state.flat[idx];
    if(!item) return;
    navTo('report');
    $('rJudge').value = `${item.title}；目前判定風險為${item.severity}。`;
    $('rAdvice').value = (item.fix || []).join('、');
    $('rNote').value = `建議測試：${(item.tests || []).join('、')}`;
    ['rJudge','rAdvice','rNote'].forEach(id=>$(id).dispatchEvent(new Event('input')));
    this.open();
    this.append('bot', `已幫你把 <b>${esc(item.title)}</b> 的判讀帶入檢測結論單，你可以直接補上客人描述後列印或保存。`);
  },
  searchScenarios(q){
    const raw = normalizeAiText(q);
    const terms = aiExpandTerms(raw);
    const queryGram = aiBigramSet(raw + ' ' + terms.join(' '));
    const seen = new Set();
    return state.flat.map(item=>{
      const hayRaw = [item.title, item.catLabel, ...(item.steps||[]), ...(item.causes||[]), ...(item.tests||[]), ...(item.fix||[])].join(' ');
      const hay = normalizeAiText(hayRaw);
      const hayCompact = hay.replace(/\s+/g,'');
      const hayGram = aiBigramSet(hay);
      let score = 0;
      let intentBonus = 0;

      for(const t of terms){
        if(t.length < 2) continue;
        if(hay.includes(t)) score += t.length >= 4 ? 5.5 : 3.2;
        else {
          const compact = t.replace(/\s+/g,'');
          if(compact.length >= 2 && hayCompact.includes(compact)) score += 2.8;
        }
      }

      const similarity = aiJaccard(queryGram, hayGram);
      score += similarity * 10;

      if(/無法開機|完全沒反應|不過電|斷電/.test(raw) && /開機|電源|不過電|斷電|沒反應/.test(hay)) intentBonus += 5.5;
      if(/黑畫面|無訊號|顯示|螢幕/.test(raw) && /黑畫面|無訊號|顯示|破圖|外接|螢幕|無畫面/.test(hay)) intentBonus += 5.2;
      if(/當機|系統不穩|卡頓|freeze|lag/.test(raw) && /當機|過熱|慢|ssd|ram|藍屏|系統|桌面|重開機/.test(hay)) intentBonus += 4.6;
      if(/wifi|網路異常|網路|連不上|無線/.test(raw) && /網路|wifi|乙太|有線|無線|連線/.test(hay)) intentBonus += 5;
      if(/更新|windows更新失敗|修復|無法進入/.test(raw) && /更新|修復|系統|boot|bitlocker|登入後黑畫面|桌面不出現|自動修復/.test(hay)) intentBonus += 4.8;
      if(/藍屏|bsod|stop/.test(raw) && /藍屏|bsod|stop/.test(hay)) intentBonus += 5;
      if(/充電|電池/.test(raw) && /充電|電池|adapter|變壓器/.test(hay)) intentBonus += 4.5;

      score += intentBonus;

      return {...item, score: Number(score.toFixed(2))};
    })
    .filter(x=>x.score>0.95)
    .sort((a,b)=>b.score-a.score)
    .filter(x=>{
      const key = `${x.catKey}__${x.title}`.toLowerCase();
      if(seen.has(key)) return false;
      seen.add(key);
      return true;
    });
  },
  matchGroups(q){
    const raw = normalizeAiText(q);
    const groups = new Map();
    this.searchScenarios(q).forEach(x=>{
      if(x.catLabel) groups.set(x.catLabel, Math.max(groups.get(x.catLabel)||0, x.score));
    });
    state.flat.forEach(item=>{
      const name = normalizeAiText(item.catLabel || '');
      if(name && (raw.includes(name) || name.includes(raw))){
        groups.set(item.catLabel, Math.max(groups.get(item.catLabel)||0, 2));
      }
    });
    return [...groups.entries()].sort((a,b)=>b[1]-a[1]).map(x=>x[0]).slice(0,4);
  }
};
window.AI_HELPER = AI_HELPER;


document.addEventListener('DOMContentLoaded', ()=>{
  flattenData();
  fillStats();
  renderDashboard();
  populateCategories();
  renderRecent();
  renderCodeShortcuts();
  renderSymptoms();
  bindReportInputs();
  buildSearchResults();
  checkStorageLamp();

  document.querySelectorAll('.navbtn[data-page]').forEach(a=>a.addEventListener('click', e=>{ e.preventDefault(); navTo(a.dataset.page); }));
  $('diagCat').addEventListener('change', renderDiagItems);
  $('diagItem').addEventListener('change', renderCurrentDiagnosis);
  $('saveRecentBtn').addEventListener('click', addRecent);
  $('copySummaryBtn').addEventListener('click', copySummary);
  $('runSearchBtn').addEventListener('click', buildSearchResults);
  $('resetSearchBtn').addEventListener('click', ()=>{ $('codeSearch').value=''; $('codeFilter').value='all'; buildSearchResults(); });
  $('codeSearch').addEventListener('keydown', e=>{ if(e.key==='Enter') buildSearchResults(); });
  $('codeFilter').addEventListener('change', buildSearchResults);
  $('runSymptomBtn').addEventListener('click', runSymptomJudge);
  $('clearSymptomBtn').addEventListener('click', clearSymptoms);
  $('fillFromSelectionBtn').addEventListener('click', fillFromSelection);
  $('printReportBtn').addEventListener('click', ()=>window.print());
  $('clearReportBtn').addEventListener('click', clearReport);
  $('mobileMenuBtn').addEventListener('click', toggleMobileMenu);
  $('mobileOverlay').addEventListener('click', closeMobileMenu);
  $('aiFab').addEventListener('click', ()=>AI_HELPER.toggle());
  $('aiCloseBtn').addEventListener('click', ()=>AI_HELPER.close());
  $('aiForm').addEventListener('submit', e=>{ e.preventDefault(); const v=$('aiInput').value; $('aiInput').value=''; AI_HELPER.open(); AI_HELPER.ask(v); });
  document.querySelectorAll('[data-ai-quick]').forEach(btn=>btn.addEventListener('click', ()=>{ AI_HELPER.open(); AI_HELPER.ask(btn.dataset.aiQuick || btn.textContent || ''); }));
});

window.addEventListener('load', ()=>{
  document.querySelectorAll('.navbtn[data-page]').forEach(a=>{
    if(!a.dataset.bound){
      a.dataset.bound = '1';
      a.addEventListener('click', e=>{ e.preventDefault(); navTo(a.dataset.page); });
    }
  });
});

</script>

